async function highlightCode(code: string, language: string = "svelte"): Promise<string> {
	const cachedCode = highlightCodeCache.get(code);
	if (cachedCode) return cachedCode;

	const highlighter = await highlighterPromise;

	const html = highlighter.codeToHtml(formatCode(code), {
		lang: language,
		themes: {
			dark: "github-dark",
			light: "github-light-default",
		},
		transformers: [
			{
				pre(node) {
					node.properties["class"] =
						"no-scrollbar min-w-0 overflow-x-auto px-4 py-3.5 outline-none has-[[data-highlighted-line]]:px-0 has-[[data-line-numbers]]:px-0 has-[[data-slot=tabs]]:p-0 !bg-transparent";
				},
				code(node) {
					node.properties["data-line-numbers"] = "";
				},
				line(node) {
					node.properties["data-line"] = "";
				},
			},
		],
	});

	highlightCodeCache.set(code, html);

	return html;
}

function createFontItem(definition: FontDefinition, role: "body" | "heading") {
	return {
		name: role === "body" ? `font-${definition.name}` : `font-heading-${definition.name}`,
		title: role === "body" ? definition.title : `${definition.title} (Heading)`,
		type: "registry:font",
		font: {
			family: definition.family,
			provider: definition.provider,
			variable: role === "body" ? definition.registryVariable : "--font-heading",
			...(definition.weight ? { weight: [...definition.weight] } : {}),
			subsets: [...definition.subsets],
			import: definition.import,
			dependency: definition.dependency,
		},
	} satisfies RegistryItem;
}

function preflightInit(cwd: string, options: { skipPreflight: boolean }) {
	const sveltePkg = getDependencyPackageInfo(cwd, "svelte")?.pkg;
	const tailwindPkg = getDependencyPackageInfo(cwd, "tailwindcss")?.pkg;

	const pkg = project.getPackageInfo(cwd);
	const deps = { ...pkg.dependencies, ...pkg.devDependencies };

	const svelte = sveltePkg?.version ?? deps["svelte"];
	const tailwindcss = tailwindPkg?.version ?? deps["tailwindcss"];

	const result = checkInitDependencies({ svelte, tailwindcss });
	if (result.ok) return;

	if (!options.skipPreflight) throw result.error;

	p.note(
		`${color.red(result.error.message)}\nContinuing initialization with ${color.bold("--skip-preflight")}.`
	);
}

function parseStyleCss(css: string): Record<string, string> {
	const ast = parseCss(css);
	const styles: Record<string, string> = {};

	ast.walkRules((rule) => {
		// Extract class name from selector (e.g., ".cn-accordion-item" -> "cn-accordion-item")
		const selector = rule.selector;
		if (!selector.startsWith(".cn-")) return;

		const className = selector.slice(1); // Remove leading "."

		// Find @apply rules within this rule
		rule.walkAtRules("apply", (atRule) => {
			const applyValue = atRule.params.trim();
			if (applyValue) {
				// If there are multiple @apply rules, concatenate them
				if (styles[className]) {
					styles[className] += ` ${applyValue}`;
				} else {
					styles[className] = applyValue;
				}
			}
		});
	});

	return styles;
}

async function ShowcaseLayout({
  children,
  params,
}: {
  children: ReactNode;
  params: Promise<{lang: string}>;
}) {
  const {lang} = await params;

  if (!hasLocale(lang)) notFound();

  const dict = await getDictionary(lang);
  const {showcase} = dict;

  return (
    <main className="container mx-auto px-6 py-12">
      <div className="mx-auto max-w-[68rem]">
        <h1 className="mb-2 text-4xl font-bold tracking-tight">{showcase.heading}</h1>
        <p className="mb-12 text-lg font-light text-muted">{showcase.description}</p>
        {children}
      </div>
    </main>
  );
}

function ShowcasesList({showcaseId}: {showcaseId: string}) {
  const params = useParams<{lang?: string}>();
  const lang = params.lang ?? i18n.defaultLanguage;
  const searchParams = useSearchParams();
  const allShowcases = getAllShowcases();
  const returnUrl = searchParams.get("returnUrl");
  const queryString = returnUrl ? `?returnUrl=${encodeURIComponent(returnUrl)}` : "";

  return (
    <div className="flex h-full flex-col items-center justify-center gap-3 p-4">
      {allShowcases.map((item) => (
        <ShowcaseItem
          key={item.name}
          isMinimal
          aria-label={item.title}
          href={`/${lang}/showcase/${item.name}${queryString}`}
          isSelected={item.name === showcaseId}
          item={item}
        />
      ))}
    </div>
  );
}

function BaseColorSlider() {
  const [variables, setVariables] = useVariablesState();
  const {base, hue} = variables;
  const dict = useDictionary().themeBuilder.baseColor;

  const handleBaseSliderChange = (value: number) => {
    setVariables({
      ...variables,
      base: value,
    });
  };

  return (
    <div className="flex flex-col gap-1">
      <LockableLabel label={dict.label} tooltip={dict.tooltip} variable="base" />
      <ChromaSlider
        className="h-6 w-[160px]"
        hue={hue}
        value={base}
        onChange={handleBaseSliderChange}
      />
    </div>
  );
}

function findMatchingTheme(currentValues: ThemeValues): ThemeId | undefined {
  for (const themeId of themeIds) {
    const themeValues = themeValuesById[themeId];
    const matches = themeComparisonKeys.every((key) => {
      const current = currentValues[key];
      const theme = themeValues[key];

      // For numbers, use approximate comparison to handle floating point
      if (typeof current === "number" && typeof theme === "number") {
        return Math.abs(current - theme) < 0.0001;
      }

      return current === theme;
    });

    if (matches) {
      return themeId;
    }
  }

  return undefined;
}

function generateFontFaceCSS(fontFamily: string, url: string): string {
  // Detect variable fonts by URL patterns
  const isVariable = url.includes(":vf@") || url.includes("-wght-") || url.includes("-opsz-");

  // Determine format based on file extension and variable font status
  let format = "woff2";

  if (url.endsWith(".woff")) {
    format = "woff";
  } else if (url.endsWith(".ttf")) {
    format = "truetype";
  } else if (url.endsWith(".otf")) {
    format = "opentype";
  } else if (isVariable && url.endsWith(".woff2")) {
    format = "woff2-variations";
  }

  // Variable fonts support weight range, static fonts use 400
  const fontWeight = isVariable ? "100 900" : "400";

  return `
@font-face {
  font-family: '${fontFamily}';
  font-style: normal;
  font-display: swap;
  font-weight: ${fontWeight};
  src: url(${url}) format('${format}');
}
`.trim();
}

function ColorSlider({
  className,
  orientation = "horizontal",
  thumbBackground,
  trackBackground,
  ...props
}: ColorSliderProps) {
  return (
    <AriaColorSlider
      className={cn("group flex w-full flex-col gap-1", className)}
      orientation={orientation}
      {...props}
    >
      <SliderTrack
        className={colorSliderTrackStyles({orientation})}
        style={({defaultStyle}) => ({
          background: trackBackground || `${defaultStyle.background}`,
        })}
      >
        <ColorThumb
          className={cn(colorThumbStyles(), orientation === "horizontal" ? "top-1/2" : "left-1/2")}
          style={({color}) => ({
            background: thumbBackground || color.toString("css"),
          })}
        />
      </SliderTrack>
    </AriaColorSlider>
  );
}

function ColorSwatchPickerItem({
  className,
  outlineColor,
  outlineOffsetColor,
  ...props
}: Omit<ColorSwatchPickerItemProps, "className"> & {
  className?: string;
  outlineColor?: string;
  outlineOffsetColor?: string;
}) {
  return (
    <AriaColorSwatchPickerItem {...props} className={itemStyles}>
      {({isSelected}) => (
        <>
          <ColorSwatch className={className} />
          <div
            className={focusIndicator({isSelected})}
            data-selected={isSelected}
            style={{
              borderColor: outlineColor,
              outlineColor: outlineOffsetColor,
            }}
          />
        </>
      )}
    </AriaColorSwatchPickerItem>
  );
}

function ComponentImagePair({
  alt,
  darkSrc,
  height = 594,
  lightSrc,
  width = 874,
}: {
  alt: string;
  darkSrc: string;
  height?: number;
  lightSrc: string;
  width?: number;
}) {
  return (
    <>
      <Image
        alt={alt}
        className="absolute inset-0 block h-full w-full object-cover dark:hidden"
        height={height}
        src={lightSrc}
        width={width}
      />
      <Image
        alt={alt}
        className="absolute inset-0 hidden h-full w-full object-cover dark:block"
        height={height}
        src={darkSrc}
        width={width}
      />
    </>
  );
}

function NavbarLinkItem({
  className,
  item,
  ...props
}: {item: LinkItemType} & HTMLAttributes<HTMLElement>) {
  if (item.type === "custom") return item.children;

  if (item.type === "menu") {
    return <NavbarLinkItemMenu className={className} item={item} {...props} />;
  }

  return (
    <LinkItem
      item={item}
      className={cn(
        "text-fd-muted-foreground hover:text-fd-accent-foreground data-[active=true]:text-fd-foreground text-sm transition-colors",
        className,
      )}
      {...props}
    >
      {item.text}
    </LinkItem>
  );
}

function TOCItems({className, ref, ...props}: TOCItemsProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const items = useTOCItems();

  if (items.length === 0) return null;

  return (
    <div className="relative">
      <TocThumb containerRef={containerRef} />
      <div
        ref={mergeRefs(ref, containerRef)}
        className={cn("border-fd-foreground/10 flex flex-col border-s", className)}
        {...props}
      >
        {items.map((item) => (
          <TOCItem key={item.url} item={item} />
        ))}
      </div>
    </div>
  );
}

function ThemeBackground() {
  const lightBg = `${siteConfig.cdnUrl}/backgrounds/docs-light-bg.jpg`;
  const darkBg = `${siteConfig.cdnUrl}/backgrounds/docs-dark-bg.jpg`;

  return (
    <>
      {/* Light theme background */}
      <Image
        fill
        priority
        alt=""
        className="fixed inset-0 z-0 object-cover object-center dark:hidden"
        quality={100}
        src={lightBg}
      />
      {/* Dark theme background */}
      <Image
        fill
        priority
        alt=""
        className="fixed inset-0 z-0 hidden object-cover object-center dark:block"
        quality={100}
        src={darkBg}
      />
    </>
  );
}

