const PopoverArrow = ({children, className, ...props}: PopoverArrowProps) => {
  const defaultArrow = (
    <svg
      data-slot="popover-overlay-arrow"
      fill="none"
      height="12"
      viewBox="0 0 12 12"
      width="12"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path d="M0 0C5.48483 8 6.5 8 12 0Z" />
    </svg>
  );

  const arrow = React.isValidElement(children)
    ? React.cloneElement(
        children as React.ReactElement<{
          className?: string;
          "data-slot"?: "popover-overlay-arrow";
        }>,
        {
          "data-slot": "popover-overlay-arrow",
        },
      )
    : defaultArrow;

  return (
    <OverlayArrow data-slot="popover-overlay-arrow-group" {...props} className={className}>
      {arrow}
    </OverlayArrow>
  );
};

const SearchFieldSearchIcon = <E extends keyof React.JSX.IntrinsicElements = "svg">({
  children,
  className,
  ...props
}: SearchFieldSearchIconProps<E> &
  Omit<React.JSX.IntrinsicElements[E], keyof SearchFieldSearchIconProps<E>>) => {
  const {slots} = useContext(SearchFieldContext);

  if (children && React.isValidElement(children)) {
    return React.cloneElement(
      children as React.ReactElement<{
        className?: string;
        "data-slot"?: string;
      }>,
      {
        ...(props as any),
        className: composeSlotClassName(slots?.searchIcon, className),
        "data-slot": "search-field-search-icon",
      },
    );
  }

  return (
    <IconSearch
      className={composeSlotClassName(slots?.searchIcon, className)}
      data-slot="search-field-search-icon"
      {...(props as any)}
    />
  );
};

function ColorSlider({
  channel,
  className,
  colorSpace,
  orientation = "horizontal",
}: ColorSliderProps) {
  return (
    <AriaColorSlider
      channel={channel}
      className={cn("group flex w-full flex-col gap-1", className)}
      colorSpace={colorSpace}
      orientation={orientation}
    >
      <SliderTrack
        className={colorSliderTrackStyles({orientation})}
        style={({defaultStyle}) => ({
          background: `${defaultStyle.background}`,
        })}
      >
        <ColorThumb
          className={cn(colorThumbStyles(), orientation === "horizontal" ? "top-1/2" : "left-1/2")}
          style={({color}) => ({
            background: color.toString("css"),
          })}
        />
      </SliderTrack>
    </AriaColorSlider>
  );
}
